--- Generate cryptographically secure random bytes
-- Uses OpenSSL's CSPRNG via OpenResty bindings
-- @param length number of random bytes to generate
-- @return string of random bytes, or nil and error message
local function secure_random_bytes(length)
    if not length or length <= 0 then
        return nil, "invalid length"
    end

    -- Preferred: use resty.openssl.rand (OpenSSL's CSPRNG)
    if ok_openssl_rand then
        local bytes, err = openssl_rand.bytes(length)
        if bytes then
            return bytes
