    f:close()
    if not bytes or #bytes ~= length then
        return nil, "failed to read sufficient bytes from /dev/urandom"
    end
    return bytes
end

--- Convert binary bytes to hexadecimal string
-- @param bytes binary string
-- @return hex-encoded string
local function bytes_to_hex(bytes)
    if ok_resty_string then
        return resty_string.to_hex(bytes)
    end
