    local hex = {}
    for i = 1, #bytes do
        hex[i] = string.format("%02x", string.byte(bytes, i))
    end
    return table.concat(hex)
end

--- Convert binary bytes to URL-safe base64
-- @param bytes binary string
-- @return base64url-encoded string
local function bytes_to_base64url(bytes)
    local b64 = ngx.encode_base64(bytes)
    if not b64 then
        return nil, "base64 encoding failed"
    end
    -- Convert to URL-safe base64: replace + with -, / with _, remove =
    b64 = b64:gsub("+", "-"):gsub("/", "_"):gsub("=", "")
    return b64
end

