--- Generate a signed session token with HMAC for integrity verification
-- Token format: <random_payload_base64url>.<timestamp>.<hmac_base64url>
-- @param options table with optional fields: length (bytes), ttl (seconds)
-- @return signed_token string, or nil and error message
function _M.generate_signed_session_token(options)
    options = options or {}
    local byte_length = options.length or TOKEN_BYTE_LENGTH

    if not ok_openssl_hmac then
        return nil, "resty.openssl.hmac not available - cannot create signed tokens"
    end

    local signing_key, key_err = get_signing_key()
    if not signing_key then
        return nil, "signing key unavailable: " .. (key_err or "unknown error")
    end

    -- Generate random payload
    local payload_bytes, err = secure_random_bytes(byte_length)
    if not payload_bytes then
        return nil, "failed to generate token payload: " .. (err or "unknown error")
    end

    local payload_b64, b64_err = bytes_to_base64url(payload_bytes)
    if not payload_b64 then
        return nil, "failed to encode payload: " .. (b64_err or "unknown error")
    end

    -- Add timestamp for expiration checking
    local timestamp = tostring(ngx.time())

    -- Create the message to sign
    local message = payload_b64 .. "." .. timestamp

    -- Compute HMAC-SHA256
    local mac, hmac_err = openssl_hmac.new(signing_key, HMAC_ALGORITHM)
    if not mac then
        return nil, "failed to create HMAC: " .. (hmac_err or "unknown error")
    end

    local ok_update, update_err = mac:update(message)
    if not ok_update then
        return nil, "HMAC update failed: " .. (update_err or "unknown error")
    end

    local digest, digest_err = mac:final()
    if not digest then
        return nil, "HMAC final failed: " .. (digest_err or "unknown error")
    end

    local signature_b64, sig_err = bytes_to_base64url(digest)
    if not signature_b64 then
        return nil, "failed to encode signature: " .. (sig_err or "unknown error")
    end

    return message .. "." .. signature_b64
end

--- Verify a signed session token
-- @param token the signed token string
-- @param options table with optional fields: max_age (seconds, default 86400)
-- @return boolean valid, string error_message
function _M.verify_signed_session_token(token, options)
    options = options or {}
    local max_age = options.max_age or 86400 -- default 24 hours

    if not ok_openssl_hmac then
        return false, "resty.openssl.hmac not available"
    end

    if not token or type(token) ~= "string" then
        return false, "invalid token"
    end

    local signing_key, key_err = get_signing_key()
    if not signing_key then
        return false, "signing key unavailable: " .. (key_err or "unknown error")
    end

    -- Parse token: <payload>.<timestamp>.<signature>
    local payload, timestamp_str, signature = token:match("^([^%.]+)%.(%d+)%.([^%.]+)$")
    if not payload or not timestamp_str or not signature then
        return false, "malformed token"
    end

    -- Check timestamp / expiration
    local token_time = tonumber(timestamp_str)
    if not token_time then
        return false, "invalid timestamp"
    end

    local current_time = ngx.time()
    if current_time - token_time > max_age then
        return false, "token expired"
    end

    -- Reject tokens from the future (clock skew tolerance: 60 seconds)
    if token_time > current_time + 60 then
        return false, "token timestamp in the future"
    end

    -- Recompute HMAC
    local message = payload .. "." .. timestamp_str

    local mac, hmac_err = openssl_hmac.new(signing_key, HMAC_ALGORITHM)
    if not mac then
        return false, "failed to create HMAC: " .. (hmac_err or "unknown error")
    end

    local ok_update, update_err = mac:update(message)
    if not ok_update then
        return false, "HMAC update failed: " .. (update_err or "unknown error")
    end

    local expected_digest, digest_err = mac:final()
    if not expected_digest then
        return false, "HMAC final failed: " .. (digest_err or "unknown error")
    end

    local expected_signature, sig_err = bytes_to_base64url(expected_digest)
    if not expected_signature then
        return false, "failed to encode expected signature: " .. (sig_err or "unknown error")
    end

    -- Constant-time comparison to prevent timing attacks
    if not _M.constant_time_compare(signature, expected_signature) then
        return false, "invalid signature"
    end

    return true, nil
end

--- Constant-time string comparison to prevent timing attacks
-- @param a first string
-- @param b second string
-- @return boolean true if strings are equal
function _M.constant_time_compare(a, b)
    if type(a) ~= "string" or type(b) ~= "string" then
        return false
    end

    if #a ~= #b then
        return false
    end

    local result = 0
    for i = 1, #a do
        result = bit.bor(result, bit.bxor(string.byte(a, i), string.byte(b, i)))
    end

    return result == 0
end

--- Generate an encrypted session payload using AES-256-GCM (authenticated encryption)
-- @param plaintext the session data to encrypt (string, typically JSON)
-- @param options table with optional fields: aad (additional authenticated data)
-- @return encrypted_payload string (base64url), or nil and error message
function _M.encrypt_session_data(plaintext, options)
    options = options or {}

    if not ok_openssl_cipher then
        return nil, "resty.openssl.cipher not available"
    end

    if not plaintext or type(plaintext) ~= "string" then
        return nil, "invalid plaintext"
    end

    local signing_key, key_err = get_signing_key()
    if not signing_key then
        return nil, "encryption key unavailable: " .. (key_err or "unknown error")
    end

    -- Derive a 32-byte encryption key from the signing key using a simple approach
    -- In production, consider using HKDF for proper key derivation
