    if ok_openssl_hmac then
        local kdf_mac, kdf_err = openssl_hmac.new(signing_key, "sha256")
        if not kdf_mac then
            return nil, "key derivation failed: " .. (kdf_err or "unknown error")
        end
        kdf_mac:update("session-encryption-key-v1")
        key_bytes = kdf_mac:final()
    else
        return nil, "HMAC not available for key derivation"
    end

    -- Generate a 12-byte IV/nonce for AES-256-GCM
    local iv, iv_err = secure_random_bytes(12)
    if not iv then
        return nil, "failed to generate IV: " .. (iv_err or "unknown error")
    end

    -- Encrypt with AES-256-GCM (authenticated encryption)
    local aes, aes_err = openssl_cipher.new("aes-256-gcm")
    if not aes then
        return nil, "failed to create cipher: " .. (aes_err or "unknown error")
    end

    local encrypted, enc_err = aes:encrypt(key_bytes, iv, plaintext, false, options.aad)
    if not encrypted then
        return nil, "encryption failed: " .. (enc_err or "unknown error")
    end

    local tag, tag_err = aes:get_aead_tag()
    if not tag then
        return nil, "failed to get auth tag: " .. (tag_err or "unknown error")
    end

    -- Combine: iv || tag || ciphertext, then base64url encode
    local combined = iv .. tag .. encrypted
    return bytes_to_base64url(combined)
