--- Decrypt an encrypted session payload
-- @param encrypted_payload base64url-encoded encrypted data
-- @param options table with optional fields: aad (additional authenticated data)
-- @return plaintext string, or nil and error message
function _M.decrypt_session_data(encrypted_payload, options)
    options = options or {}

    if not ok_openssl_cipher then
        return nil, "resty.openssl.cipher not available"
    end

    if not encrypted_payload or type(encrypted_payload) ~= "string" then
        return nil, "invalid encrypted payload"
    end

    local signing_key, key_err = get_signing_key()
    if not signing_key then
        return nil, "decryption key unavailable: " .. (key_err or "unknown error")
    end

    -- Derive the same encryption key
    local key_bytes
    if ok_openssl_hmac then
        local kdf_mac, kdf_err = openssl_hmac.new(signing_key, "sha256")
        if not kdf_mac then
            return nil, "key derivation failed: " .. (kdf_err or "unknown error")
        end
        kdf_mac:update("session-encryption-key-v1")
        key_bytes = kdf_mac:final()
    else
        return nil, "HMAC not available for key derivation"
    end

    -- Decode from base64url
    local b64 = encrypted_payload:gsub("-", "+"):gsub("_", "/")
    local padding = (4 - #b64 % 4) % 4
    b64 = b64 .. string.rep("=", padding)
    local combined = ngx.decode_base64(b64)
    if not combined then
        return nil, "base64 decoding failed"
    end

    -- Extract iv (12 bytes), tag (16 bytes), ciphertext (rest)
    if #combined < 28 then -- 12 + 16 minimum
        return nil, "encrypted payload too short"
    end

    local iv = combined:sub(1, 12)
    local tag = combined:sub(13, 28)
    local ciphertext = combined:sub(29)

    -- Decrypt with AES-256-GCM
    local aes, aes_err = openssl_cipher.new("aes-256-gcm")
    if not aes then
        return nil, "failed to create cipher: " .. (aes_err or "unknown error")
    end

    local plaintext, dec_err = aes:decrypt(key_bytes, iv, ciphertext, false, options.aad, tag)
    if not plaintext then
        return nil, "decryption failed (data may be tampered): " .. (dec_err or "unknown error")
    end

    return plaintext
end

